import React, { useEffect, useState } from "react";
import API from "../../api/api";

const RateFreelancer = () => {
  const [projects, setProjects]   = useState([]);
  const [loading, setLoading]     = useState(true);
  const [modal, setModal]         = useState(null); // { project, freelancer_id, freelancer_name }
  const [rating, setRating]       = useState(5);
  const [review, setReview]       = useState("");
  const [hover, setHover]         = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState({}); // project_id → true

  useEffect(() => {
    const fetch = async () => {
      try {
        // Get accepted proposals for client's projects
        const projRes = await API.get("/projects/client");
        const projects = projRes.data || [];
        // For each project get proposals
        const withProposals = await Promise.all(
          projects.map(async (p) => {
            try {
              const propRes = await API.get(`/proposals/project/${p.id}`);
              const accepted = propRes.data?.find(pr => pr.status === "accepted");
              return { ...p, acceptedProposal: accepted || null };
            } catch { return { ...p, acceptedProposal: null }; }
          })
        );
        setProjects(withProposals.filter(p => p.acceptedProposal));
      } catch {}
      setLoading(false);
    };
    fetch();
  }, []);

  const openModal = (project) => {
    setModal({ project, freelancer_id: project.acceptedProposal.freelancer_id, freelancer_name: project.acceptedProposal.freelancer_name });
    setRating(5); setReview("");
  };

  const submitReview = async () => {
    setSubmitting(true);
    try {
      await API.post("/reviews", {
        project_id: modal.project.id,
        freelancer_id: modal.freelancer_id,
        rating, review
      });
      setSubmitted(prev => ({ ...prev, [modal.project.id]: true }));
      setModal(null);
      alert("⭐ Review submitted!");
    } catch { alert("Error submitting review"); }
    setSubmitting(false);
  };

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-3xl mx-auto">
        <h1 className="text-2xl font-bold text-gray-800 mb-2">Rate Freelancers</h1>
        <p className="text-gray-500 mb-6">Review freelancers for your accepted projects</p>

        {projects.length === 0 ? (
          <div className="bg-white rounded-xl p-10 text-center shadow text-gray-400">
            <div className="text-5xl mb-3">⭐</div>
            No accepted projects to review yet.
          </div>
        ) : (
          <div className="space-y-4">
            {projects.map(p => (
              <div key={p.id} className="bg-white rounded-xl shadow p-5 border border-gray-100">
                <div className="flex justify-between items-center">
                  <div>
                    <h3 className="font-bold text-gray-800">{p.title}</h3>
                    <p className="text-sm text-gray-500 mt-0.5">
                      Freelancer: <span className="font-medium text-gray-700">{p.acceptedProposal.freelancer_name}</span>
                    </p>
                    <p className="text-sm text-teal-600 font-semibold">Bid: ₹{p.acceptedProposal.bid}</p>
                  </div>
                  {submitted[p.id] ? (
                    <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-sm font-medium">✓ Reviewed</span>
                  ) : (
                    <button onClick={() => openModal(p)}
                      className="bg-yellow-400 hover:bg-yellow-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
                      ⭐ Rate
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* RATING MODAL */}
      {modal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-1">Rate Freelancer</h2>
            <p className="text-gray-500 text-sm mb-5">{modal.freelancer_name} — {modal.project.title}</p>

            {/* STAR RATING */}
            <div className="mb-5">
              <label className="block text-sm font-medium text-gray-700 mb-2">Rating</label>
              <div className="flex gap-1">
                {[1,2,3,4,5].map(star => (
                  <button key={star}
                    onMouseEnter={() => setHover(star)}
                    onMouseLeave={() => setHover(0)}
                    onClick={() => setRating(star)}
                    className={`text-3xl transition ${(hover || rating) >= star ? "text-yellow-400" : "text-gray-300"}`}>
                    ★
                  </button>
                ))}
                <span className="ml-2 self-center text-gray-600 font-medium">{rating}/5</span>
              </div>
            </div>

            <div className="mb-5">
              <label className="block text-sm font-medium text-gray-700 mb-1">Review (optional)</label>
              <textarea rows={3} value={review} onChange={e => setReview(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500 resize-none"
                placeholder="How was the work quality?" />
            </div>

            <div className="flex gap-3">
              <button onClick={submitReview} disabled={submitting}
                className="flex-1 bg-yellow-400 hover:bg-yellow-500 text-white py-2 rounded-lg font-medium disabled:opacity-50">
                {submitting ? "Submitting..." : "Submit Review"}
              </button>
              <button onClick={() => setModal(null)}
                className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 py-2 rounded-lg font-medium">
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RateFreelancer;
